 1	import * as React from 'react';
 2	
 3	import {
 4	  GreenCheckCircleIcon,
 5	  YellowExclamationTriangleIcon,
 6	} from '@openshift-console/dynamic-plugin-sdk';
 7	import { Flex, FlexItem, Tooltip } from '@patternfly/react-core';
 8	
 9	import { GrayUnknownIcon } from '../status/icons';
10	
11	interface SyncProps {
12	  tooltip: any[];
13	  count: number;
14	  icon: string;
15	}
16	
17	const SyncFragment: React.FC<SyncProps> = ({ tooltip, count, icon }) => {
18	  let targetIcon: React.ReactNode;
19	  if (icon === 'check') {
20	    targetIcon = <GreenCheckCircleIcon />;
21	  } else if (icon === 'exclamation') {
22	    targetIcon = <YellowExclamationTriangleIcon />;
23	  } else {
24	    targetIcon = <GrayUnknownIcon />;
25	  }
26	  return (
27	    <Flex flex={{ default: 'flex_1' }}>
28	      <FlexItem>
29	        {count > 0 ? (
30	          <Tooltip isContentLeftAligned content={<div>{tooltip}</div>}>
31	            <div>
32	              {targetIcon} {count}
33	            </div>
34	          </Tooltip>
35	        ) : (
36	          <div>
37	            {targetIcon} {count}
38	          </div>
39	        )}
40	      </FlexItem>
41	    </Flex>
42	  );
43	};
44	
45	export default SyncFragment;

